import anthropic, json

client = anthropic.Anthropic()

def draft_ai_output_ip_policy_clause(
    organisation_type: str,     # "SaaS vendor", "law firm", "bank", "consulting"
    primary_output_types: list[str],
    client_deliverable: bool,
    employees_or_contractors: str,  # "employees", "contractors", "both"
    jurisdiction: str,
) -> dict:
    """
    Draft IP policy clauses specifically covering AI-generated outputs.
    Returns clauses suitable for insertion into an employment agreement,
    contractor agreement, or client services agreement.
    """
    prompt = f"""
You are a technology transactions lawyer drafting AI-specific IP policy clauses.

Organisation type: {organisation_type}
Primary AI output types: {', '.join(primary_output_types)}
Outputs delivered to clients: {client_deliverable}
Workforce type: {employees_or_contractors}
Jurisdiction: {jurisdiction}

Draft three sets of policy clauses:
1. Internal IP ownership clause (for employment/contractor agreements)
2. Client-facing IP assignment clause (for services agreements, if client_deliverable is true)
3. AI disclosure clause (obligation to disclose AI use to clients or recipients)

Each clause should be precise, use defined terms, and address the specific uncertainty
about whether AI outputs are copyright-protected.

Return ONLY JSON:
{{
  "internal_ip_clause": "<string>",
  "client_ip_clause": "<string or null>",
  "ai_disclosure_clause": "<string>",
  "drafting_notes": ["<string>", ...],
  "recommended_defined_terms": {{"term": "definition", ...}}
}}
""".strip()

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=900,
        messages=[{"role": "user", "content": prompt}]
    )
    return json.loads(response.content[0].text)
